parameters.jsCode:
const aiText = $input.item.json.choices[0].message.content;
const prev   = $('Map & Prepare Data').item.json;

const deptMatch     = aiText.match(/DEPARTMENT:\s*(\w+)/i);
const priorityMatch = aiText.match(/PRIORITY:\s*(\w+)/i);
const summaryMatch  = aiText.match(/SUMMARY:\s*(.+)/i);

const dept     = deptMatch     ? deptMatch[1].toUpperCase().trim()  : 'OTHERS';
const priority = priorityMatch ? priorityMatch[1].trim()            : 'Medium';
const summary  = summaryMatch  ? summaryMatch[1].trim()             : prev.complaintText.slice(0, 100);

const improvedText = aiText
  .replace(/DEPARTMENT:.*$/mi, '')
  .replace(/PRIORITY:.*$/mi,   '')
  .replace(/SUMMARY:.*$/mi,    '')
  .trim();

const routingMap = {
  PENSION:  { email: 'REPLACE_WITH_PENSION_OFFICER_EMAIL@example.gov.in', label: 'DSWO (Pension)'  },
  AADHAAR:  { email: 'REPLACE_WITH_AADHAAR_OFFICER_EMAIL@example.gov.in', label: 'ADC (Aadhaar)'   },
  PPP:      { email: 'REPLACE_WITH_PPP_OFFICER_EMAIL@example.gov.in', label: 'ADC (PPP)'       },
  RATION:   { email: 'REPLACE_WITH_RATION_OFFICER_EMAIL@example.gov.in', label: 'DFSC (Ration)'   },
  REVENUE:  { email: 'REPLACE_WITH_REVENUE_OFFICER_EMAIL@example.gov.in', label: 'DRO (Revenue)'   },
  CRED:     { email: 'REPLACE_WITH_CRED_OFFICER_EMAIL@example.gov.in', label: 'ADC (CRED)'      },
  OTHERS:   { email: 'REPLACE_WITH_DEFAULT_OFFICER_EMAIL@example.gov.in', label: 'DC Office'       }
};

const route = routingMap[dept] || routingMap.OTHERS;

return {
  json: {
    ...prev,
    improvedText, dept, priority, summary,
    officerEmail: route.email,
    officerLabel: route.label
  }
};

