parameters.jsCode:
const b = $input.item.json.body;

const name          = b.name || '';
const phone         = b.phone || '';
const email         = b.email || '';
const address       = b.address || '';
const category      = b.category || 'Others';
const language      = b.language || 'English';
const complaintText = b.complaint_text || b.complaint || '';
const aiImproved    = b.ai_improved_text || '';
const submittedAt   = b.submitted_at || new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' });

let phone_clean = phone.toString().replace(/[\s\-()]/g, '');
if (!phone_clean.startsWith('+')) phone_clean = '+91' + phone_clean;

const refNumber = '#KKR' + Date.now().toString().slice(-6);

return {
  json: {
    name, phone, phone_clean, email, address,
    category, language, complaintText, aiImproved,
    submittedAt, refNumber,
    citizenWhatsApp: 'whatsapp:' + phone_clean,
    useText: aiImproved !== '' ? aiImproved : complaintText
  }
};
